import pika
import json
import time
from datetime import datetime

def publish_task(task_data, queue_name='task_queue'):
    """Publish a task message to RabbitMQ queue"""
    try:
        # Create connection parameters with default credentials
        connection_params = pika.ConnectionParameters(
            host='localhost',
            port=5672,
            credentials=pika.PlainCredentials('guest', 'guest'),
            heartbeat=600,
            blocked_connection_timeout=300
        )
        
        connection = pika.BlockingConnection(connection_params)
        channel = connection.channel()
        
        # Declare queue
        channel.queue_declare(queue=queue_name, durable=True)
        
        # Publish message
        message = json.dumps(task_data)
        channel.basic_publish(
            exchange='',
            routing_key=queue_name,
            body=message,
            properties=pika.BasicProperties(
                delivery_mode=2,  # Make message persistent
            )
        )
        
        print(f" [x] Sent task: {message}")
        connection.close()
        
    except Exception as e:
        print(f"Error publishing task: {e}")

def consume_tasks(queue_name='task_queue', callback_func=None):
    """Consume tasks from RabbitMQ queue"""
    try:
        # Create connection parameters with default credentials
        connection_params = pika.ConnectionParameters(
            host='localhost',
            port=5672,
            credentials=pika.PlainCredentials('guest', 'guest'),
            heartbeat=600,
            blocked_connection_timeout=300
        )
        
        connection = pika.BlockingConnection(connection_params)
        channel = connection.channel()
        
        # Declare queue
        channel.queue_declare(queue=queue_name, durable=True)
        
        # Set up callback function
        if callback_func is None:
            def default_callback(ch, method, properties, body):
                task = json.loads(body)
                print(f" [x] Received task: {task}")
                print(f" [x] Processing task at {datetime.now()}")
                # Simulate work
                time.sleep(1)
                print(f" [x] Completed task at {datetime.now()}")
                ch.basic_ack(delivery_tag=method.delivery_tag)
        else:
            def callback(ch, method, properties, body):
                callback_func(ch, method, properties, body)
                ch.basic_ack(delivery_tag=method.delivery_tag)
        
        channel.basic_qos(prefetch_count=1)
        channel.basic_consume(queue=queue_name, on_message_callback=callback)
        
        print(' [*] Waiting for tasks. To exit press CTRL+C')
        channel.start_consuming()
        
    except KeyboardInterrupt:
        print(" [*] Interrupted")
        connection.close()
    except Exception as e:
        print(f"Error consuming tasks: {e}")

